{
  "name": "MEI Master Control",
  "description": "Uma plataforma completa para Microempreendedores Individuais gerenciarem faturamento, despesas e saldos bancários com facilidade e segurança.",
  "requestFramePermissions": []
}

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE'
}

export interface Transaction {
  id: string;
  date: string;
  description: string;
  amount: number;
  type: TransactionType;
  category: string;
  accountId: string;
}

export interface Account {
  id: string;
  name: string;
  balance: number;
  color: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  meiName: string;
}

export interface AppState {
  transactions: Transaction[];
  accounts: Account[];
  user: User | null;
}

import { Account, Transaction, TransactionType } from './types';

export const INITIAL_ACCOUNTS: Account[] = [
  { id: '1', name: 'Conta Principal PJ', balance: 5240.50, color: 'bg-blue-600' },
  { id: '2', name: 'Caixa Físico', balance: 450.00, color: 'bg-emerald-600' },
  { id: '3', name: 'Nubank PJ', balance: 1200.00, color: 'bg-purple-600' },
];

export const CATEGORIES = {
  INCOME: ['Venda de Produtos', 'Prestação de Serviços', 'Outros'],
  EXPENSE: ['Aluguel', 'DAS-MEI', 'Fornecedores', 'Internet/Luz', 'Marketing', 'Retirada Pró-labore', 'Outros']
};

export const INITIAL_TRANSACTIONS: Transaction[] = [
  {
    id: 't1',
    date: new Date().toISOString().split('T')[0],
    description: 'Venda Consultoria TI',
    amount: 1500.00,
    type: TransactionType.INCOME,
    category: 'Prestação de Serviços',
    accountId: '1'
  },
  {
    id: 't2',
    date: new Date().toISOString().split('T')[0],
    description: 'Pagamento DAS-MEI',
    amount: 72.00,
    type: TransactionType.EXPENSE,
    category: 'DAS-MEI',
    accountId: '1'
  }
];

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import { User, Transaction, Account, TransactionType } from './types';
import { INITIAL_ACCOUNTS, INITIAL_TRANSACTIONS } from './constants';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import AccountManager from './components/AccountManager';
import Navbar from './components/Navbar';
import AddTransactionModal from './components/AddTransactionModal';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'dashboard' | 'transactions' | 'accounts'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('mei_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [accounts, setAccounts] = useState<Account[]>(() => {
    const saved = localStorage.getItem('mei_accounts');
    return saved ? JSON.parse(saved) : INITIAL_ACCOUNTS;
  });
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  useEffect(() => {
    const savedUser = localStorage.getItem('mei_user');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  useEffect(() => {
    localStorage.setItem('mei_transactions', JSON.stringify(transactions));
    localStorage.setItem('mei_accounts', JSON.stringify(accounts));
  }, [transactions, accounts]);

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('mei_user', JSON.stringify(userData));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('mei_user');
  };

  const addTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const id = Math.random().toString(36).substr(2, 9);
    const tx = { ...newTx, id };

    setTransactions(prev => [tx, ...prev]);

    // Update account balance
    setAccounts(prev => prev.map(acc => {
      if (acc.id === tx.accountId) {
        const change = tx.type === TransactionType.INCOME ? tx.amount : -tx.amount;
        return { ...acc, balance: acc.balance + change };
      }
      return acc;
    }));

    setIsAddModalOpen(false);
  };

  const deleteTransaction = (id: string) => {
    const tx = transactions.find(t => t.id === id);
    if (!tx) return;

    setTransactions(prev => prev.filter(t => t.id !== id));

    setAccounts(prev => prev.map(acc => {
      if (acc.id === tx.accountId) {
        const revert = tx.type === TransactionType.INCOME ? -tx.amount : tx.amount;
        return { ...acc, balance: acc.balance + revert };
      }
      return acc;
    }));
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Navbar 
        activeView={view} 
        setView={setView} 
        onLogout={handleLogout} 
        userName={user.meiName}
      />

      <main className="flex-grow container mx-auto px-4 py-8 pb-24 md:pb-8">
        {view === 'dashboard' && (
          <Dashboard transactions={transactions} accounts={accounts} />
        )}
        {view === 'transactions' && (
          <TransactionList 
            transactions={transactions} 
            accounts={accounts}
            onDelete={deleteTransaction} 
          />
        )}
        {view === 'accounts' && (
          <AccountManager accounts={accounts} />
        )}
      </main>

      {/* Floating Action Button for Mobile */}
      <button 
        onClick={() => setIsAddModalOpen(true)}
        className="fixed bottom-24 right-6 md:bottom-8 md:right-8 w-14 h-14 bg-blue-600 text-white rounded-full shadow-lg flex items-center justify-center text-2xl hover:bg-blue-700 transition-all z-40"
      >
        <i className="fas fa-plus"></i>
      </button>

      {isAddModalOpen && (
        <AddTransactionModal 
          onClose={() => setIsAddModalOpen(false)}
          onSubmit={addTransaction}
          accounts={accounts}
        />
      )}

      {/* Mobile Bottom Navigation */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex justify-around items-center py-3 z-30">
        <button onClick={() => setView('dashboard')} className={`flex flex-col items-center ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}>
          <i className="fas fa-home text-xl"></i>
          <span className="text-[10px] mt-1 font-medium">Início</span>
        </button>
        <button onClick={() => setView('transactions')} className={`flex flex-col items-center ${view === 'transactions' ? 'text-blue-600' : 'text-slate-400'}`}>
          <i className="fas fa-exchange-alt text-xl"></i>
          <span className="text-[10px] mt-1 font-medium">Lançamentos</span>
        </button>
        <div className="w-12 h-10"></div> {/* Spacer for FAB */}
        <button onClick={() => setView('accounts')} className={`flex flex-col items-center ${view === 'accounts' ? 'text-blue-600' : 'text-slate-400'}`}>
          <i className="fas fa-wallet text-xl"></i>
          <span className="text-[10px] mt-1 font-medium">Contas</span>
        </button>
        <button onClick={handleLogout} className="flex flex-col items-center text-slate-400">
          <i className="fas fa-sign-out-alt text-xl"></i>
          <span className="text-[10px] mt-1 font-medium">Sair</span>
        </button>
      </div>
    </div>
  );
};

export default App;

import React from 'react';

interface NavbarProps {
  activeView: string;
  setView: (view: any) => void;
  onLogout: () => void;
  userName: string;
}

const Navbar: React.FC<NavbarProps> = ({ activeView, setView, onLogout, userName }) => {
  return (
    <nav className="bg-white border-b border-slate-200 sticky top-0 z-20">
      <div className="container mx-auto px-4">
        <div className="flex justify-between items-center h-16">
          <div className="flex items-center space-x-2">
            <div className="bg-blue-600 text-white p-2 rounded-lg">
              <i className="fas fa-chart-pie text-xl"></i>
            </div>
            <span className="text-xl font-bold text-slate-800 tracking-tight">MEI<span className="text-blue-600">Master</span></span>
          </div>

          <div className="hidden md:flex space-x-8">
            <button 
              onClick={() => setView('dashboard')}
              className={`font-medium transition-colors ${activeView === 'dashboard' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
            >
              Dashboard
            </button>
            <button 
              onClick={() => setView('transactions')}
              className={`font-medium transition-colors ${activeView === 'transactions' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
            >
              Lançamentos
            </button>
            <button 
              onClick={() => setView('accounts')}
              className={`font-medium transition-colors ${activeView === 'accounts' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
            >
              Contas Bancárias
            </button>
          </div>

          <div className="flex items-center space-x-4">
            <div className="text-right hidden sm:block">
              <p className="text-sm font-semibold text-slate-800 leading-none">{userName}</p>
              <p className="text-xs text-slate-500 mt-1">Plano MEI</p>
            </div>
            <button 
              onClick={onLogout}
              className="hidden md:flex items-center text-slate-400 hover:text-red-500 transition-colors"
            >
              <i className="fas fa-sign-out-alt"></i>
            </button>
            <div className="md:hidden">
               <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-bold text-xs">
                {userName.charAt(0)}
               </div>
            </div>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Transaction, Account, TransactionType } from '../types';

interface DashboardProps {
  transactions: Transaction[];
  accounts: Account[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions, accounts }) => {
  const totalBalance = useMemo(() => accounts.reduce((sum, acc) => sum + acc.balance, 0), [accounts]);

  const monthlyData = useMemo(() => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();

    const income = transactions
      .filter(t => t.type === TransactionType.INCOME && new Date(t.date).getMonth() === currentMonth)
      .reduce((sum, t) => sum + t.amount, 0);

    const expense = transactions
      .filter(t => t.type === TransactionType.EXPENSE && new Date(t.date).getMonth() === currentMonth)
      .reduce((sum, t) => sum + t.amount, 0);

    return { income, expense, faturamento: income };
  }, [transactions]);

  // Chart data for last 6 months
  const chartData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const now = new Date();
    const data = [];

    for (let i = 5; i >= 0; i--) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const m = d.getMonth();
      const y = d.getFullYear();

      const income = transactions
        .filter(t => {
          const td = new Date(t.date);
          return td.getMonth() === m && td.getFullYear() === y && t.type === TransactionType.INCOME;
        })
        .reduce((sum, t) => sum + t.amount, 0);

      const expense = transactions
        .filter(t => {
          const td = new Date(t.date);
          return td.getMonth() === m && td.getFullYear() === y && t.type === TransactionType.EXPENSE;
        })
        .reduce((sum, t) => sum + t.amount, 0);

      data.push({
        name: months[m],
        faturamento: income,
        despesas: expense
      });
    }
    return data;
  }, [transactions]);

  const meiLimit = 81000;
  const currentYearFaturamento = transactions
    .filter(t => t.type === TransactionType.INCOME && new Date(t.date).getFullYear() === new Date().getFullYear())
    .reduce((sum, t) => sum + t.amount, 0);

  const meiProgress = Math.min((currentYearFaturamento / meiLimit) * 100, 100);

  return (
    <div className="space-y-6">
      <header>
        <h1 className="text-2xl font-bold text-slate-800">Olá, empreendedor! 👋</h1>
        <p className="text-slate-500">Aqui está um resumo do seu negócio hoje.</p>
      </header>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
          <div className="flex justify-between items-center mb-4">
            <span className="text-slate-500 font-medium">Saldo Total</span>
            <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center">
              <i className="fas fa-wallet"></i>
            </div>
          </div>
          <p className="text-3xl font-bold text-slate-800">
            {totalBalance.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
          </p>
          <div className="mt-2 text-sm">
            <span className="text-emerald-500 font-semibold">+2.5%</span> <span className="text-slate-400">vs mês anterior</span>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
          <div className="flex justify-between items-center mb-4">
            <span className="text-slate-500 font-medium">Faturamento (Mês)</span>
            <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center">
              <i className="fas fa-arrow-up"></i>
            </div>
          </div>
          <p className="text-3xl font-bold text-slate-800">
            {monthlyData.income.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
          </p>
          <div className="mt-2 text-sm">
            <span className="text-emerald-500 font-semibold">{transactions.filter(t => t.type === TransactionType.INCOME).length}</span> <span className="text-slate-400">entradas realizadas</span>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
          <div className="flex justify-between items-center mb-4">
            <span className="text-slate-500 font-medium">Despesas (Mês)</span>
            <div className="w-10 h-10 bg-rose-50 text-rose-600 rounded-full flex items-center justify-center">
              <i className="fas fa-arrow-down"></i>
            </div>
          </div>
          <p className="text-3xl font-bold text-slate-800">
            {monthlyData.expense.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
          </p>
          <div className="mt-2 text-sm text-slate-400">
             Saldo líquido: <span className="font-semibold text-slate-700">{(monthlyData.income - monthlyData.expense).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Main Chart */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Faturamento vs Despesas</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="faturamento" fill="#10b981" radius={[4, 4, 0, 0]} barSize={20} />
                <Bar dataKey="despesas" fill="#f43f5e" radius={[4, 4, 0, 0]} barSize={20} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* MEI Limit Tracker */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between">
          <div>
            <h3 className="text-lg font-bold text-slate-800 mb-1">Limite MEI (Anual)</h3>
            <p className="text-slate-500 text-sm mb-6">Acompanhe seu teto de faturamento anual.</p>

            <div className="flex justify-between mb-2">
              <span className="text-sm font-semibold text-blue-600">
                {currentYearFaturamento.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
              </span>
              <span className="text-sm text-slate-400">Limite: R$ 81.000</span>
            </div>

            <div className="w-full bg-slate-100 rounded-full h-4 overflow-hidden">
              <div 
                className={`h-full transition-all duration-1000 ${meiProgress > 90 ? 'bg-rose-500' : meiProgress > 70 ? 'bg-amber-500' : 'bg-blue-600'}`}
                style={{ width: `${meiProgress}%` }}
              ></div>
            </div>

            <div className="mt-4 p-4 bg-blue-50 rounded-xl text-blue-700 text-sm flex items-start space-x-3">
              <i className="fas fa-info-circle mt-0.5"></i>
              <p>Você utilizou <strong>{meiProgress.toFixed(1)}%</strong> do seu limite anual. Restam {(meiLimit - currentYearFaturamento).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })} para o fim do ano.</p>
            </div>
          </div>

          <div className="mt-8 border-t border-slate-100 pt-6">
             <h4 className="text-sm font-bold text-slate-800 mb-4">Contas Bancárias</h4>
             <div className="space-y-3">
               {accounts.map(acc => (
                 <div key={acc.id} className="flex justify-between items-center">
                   <div className="flex items-center space-x-3">
                     <div className={`w-2 h-2 rounded-full ${acc.color}`}></div>
                     <span className="text-sm text-slate-600">{acc.name}</span>
                   </div>
                   <span className="text-sm font-bold text-slate-800">{acc.balance.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
                 </div>
               ))}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Transaction, TransactionType, Account } from '../types';

interface TransactionListProps {
  transactions: Transaction[];
  accounts: Account[];
  onDelete: (id: string) => void;
}

const TransactionList: React.FC<TransactionListProps> = ({ transactions, accounts, onDelete }) => {
  const [filter, setFilter] = useState<'ALL' | TransactionType>('ALL');
  const [searchTerm, setSearchTerm] = useState('');

  const filtered = transactions.filter(t => {
    const matchesFilter = filter === 'ALL' || t.type === filter;
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  const getAccountName = (id: string) => accounts.find(a => a.id === id)?.name || 'N/A';

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-6 border-b border-slate-100 space-y-4">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <h2 className="text-xl font-bold text-slate-800">Extrato de Lançamentos</h2>

          <div className="flex items-center space-x-2">
            <button 
              onClick={() => setFilter('ALL')}
              className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors ${filter === 'ALL' ? 'bg-blue-600 text-white' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'}`}
            >
              Todos
            </button>
            <button 
              onClick={() => setFilter(TransactionType.INCOME)}
              className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors ${filter === TransactionType.INCOME ? 'bg-emerald-600 text-white' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'}`}
            >
              Entradas
            </button>
            <button 
              onClick={() => setFilter(TransactionType.EXPENSE)}
              className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors ${filter === TransactionType.EXPENSE ? 'bg-rose-600 text-white' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'}`}
            >
              Saídas
            </button>
          </div>
        </div>

        <div className="relative">
          <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
          <input 
            type="text"
            placeholder="Buscar por descrição ou categoria..."
            className="w-full pl-11 pr-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-blue-500 transition-all outline-none"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Data</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Descrição</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Categoria</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Conta</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Valor</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filtered.length === 0 ? (
              <tr>
                <td colSpan={6} className="px-6 py-12 text-center text-slate-400">
                  <i className="fas fa-receipt text-4xl mb-3 block"></i>
                  Nenhum lançamento encontrado.
                </td>
              </tr>
            ) : (
              filtered.map((tx) => (
                <tr key={tx.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">
                    {new Date(tx.date).toLocaleDateString('pt-BR')}
                  </td>
                  <td className="px-6 py-4 text-sm font-medium text-slate-800">
                    {tx.description}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="px-2 py-1 text-xs font-medium rounded-md bg-slate-100 text-slate-600">
                      {tx.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">
                    {getAccountName(tx.accountId)}
                  </td>
                  <td className={`px-6 py-4 whitespace-nowrap text-sm font-bold text-right ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-rose-600'}`}>
                    {tx.type === TransactionType.INCOME ? '+' : '-'} {tx.amount.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
