              <th className="px-6 py-4 text-xs font-extrabold text-slate-700 uppercase tracking-wider">Descrição</th>
              <th className="px-6 py-4 text-xs font-extrabold text-slate-700 uppercase tracking-wider">Categoria</th>
              <th className="px-6 py-4 text-xs font-extrabold text-slate-700 uppercase tracking-wider">Conta</th>
              <th className="px-6 py-4 text-xs font-extrabold text-slate-700 uppercase tracking-wider text-right">Valor</th>
              <th className="px-6 py-4 text-xs font-extrabold text-slate-700 uppercase tracking-wider text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filtered.length === 0 ? (
              <tr>
                <td colSpan={6} className="px-6 py-12 text-center text-slate-600 font-medium">
