import React, { useMemo, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Transaction, Account, TransactionType } from '../types';

interface DashboardProps {
  transactions: Transaction[];
  accounts: Account[];
}

type PeriodFilter = 'month' | 'year' | 'all';

const Dashboard: React.FC<DashboardProps> = ({ transactions, accounts }) => {
  const [filterType, setFilterType] = useState<PeriodFilter>('month');
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const d = new Date(t.date);
      if (filterType === 'month') {
        return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
      }
      if (filterType === 'year') {
        return d.getFullYear() === selectedYear;
      }
      return true;
    });
  }, [transactions, filterType, selectedMonth, selectedYear]);

  const summary = useMemo(() => {
    const income = filteredTransactions
      .filter(t => t.type === TransactionType.INCOME)
      .reduce((sum, t) => sum + t.amount, 0);

    const expense = filteredTransactions
      .filter(t => t.type === TransactionType.EXPENSE)
      .reduce((sum, t) => sum + t.amount, 0);

    return { income, expense, balance: income - expense };
  }, [filteredTransactions]);

  const totalBalance = useMemo(() => accounts.reduce((sum, acc) => sum + acc.balance, 0), [accounts]);

  const chartData = useMemo(() => {
    const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

    if (filterType === 'month') {
      // Show days of the month or just comparison? Let's show last 6 months for context
      const data = [];
      const now = new Date(selectedYear, selectedMonth);
      for (let i = 5; i >= 0; i--) {
        const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
        const m = d.getMonth();
        const y = d.getFullYear();
        const inc = transactions.filter(t => {
          const td = new Date(t.date);
          return td.getMonth() === m && td.getFullYear() === y && t.type === TransactionType.INCOME;
        }).reduce((s, t) => s + t.amount, 0);
        const exp = transactions.filter(t => {
          const td = new Date(t.date);
          return td.getMonth() === m && td.getFullYear() === y && t.type === TransactionType.EXPENSE;
        }).reduce((s, t) => s + t.amount, 0);
        data.push({ name: months[m], faturamento: inc, despesas: exp });
      }
      return data;
    } else {
      // Show all months of the selected year
      return months.map((m, idx) => {
        const inc = transactions.filter(t => {
          const td = new Date(t.date);
          return td.getMonth() === idx && td.getFullYear() === selectedYear && t.type === TransactionType.INCOME;
        }).reduce((s, t) => s + t.amount, 0);
        const exp = transactions.filter(t => {
          const td = new Date(t.date);
          return td.getMonth() === idx && td.getFullYear() === selectedYear && t.type === TransactionType.EXPENSE;
        }).reduce((s, t) => s + t.amount, 0);
        return { name: m, faturamento: inc, despesas: exp };
      });
    }
  }, [transactions, filterType, selectedMonth, selectedYear]);

  const meiLimit = 81000;
  const currentYearFaturamento = transactions
    .filter(t => t.type === TransactionType.INCOME && new Date(t.date).getFullYear() === selectedYear)
    .reduce((sum, t) => sum + t.amount, 0);
  const meiProgress = Math.min((currentYearFaturamento / meiLimit) * 100, 100);

  const monthsList = ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'];

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900">Dashboard</h1>
          <p className="text-slate-600 font-medium">Controle seu faturamento e limite MEI.</p>
        </div>

        <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-2xl shadow-sm border border-slate-200">
          <button 
            onClick={() => setFilterType('month')}
            className={`px-4 py-2 text-xs font-bold rounded-xl transition-all ${filterType === 'month' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-700 hover:bg-slate-100'}`}
          >
            Mensal
          </button>
          <button 
            onClick={() => setFilterType('year')}
            className={`px-4 py-2 text-xs font-bold rounded-xl transition-all ${filterType === 'year' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-700 hover:bg-slate-100'}`}
          >
            Anual
          </button>
          <button 
            onClick={() => setFilterType('all')}
            className={`px-4 py-2 text-xs font-bold rounded-xl transition-all ${filterType === 'all' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-700 hover:bg-slate-100'}`}
          >
            Tudo
          </button>
        </div>
      </header>

      {filterType !== 'all' && (
        <div className="flex gap-4 animate-in fade-in slide-in-from-top-2 duration-300">
          {filterType === 'month' && (
            <select 
              value={selectedMonth} 
              onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              className="bg-white border-slate-200 rounded-xl px-4 py-2 text-sm font-bold text-slate-900 shadow-sm outline-none focus:ring-2 focus:ring-blue-500"
            >
              {monthsList.map((m, i) => <option key={m} value={i}>{m}</option>)}
            </select>
          )}
          <select 
            value={selectedYear} 
            onChange={(e) => setSelectedYear(parseInt(e.target.value))}
            className="bg-white border-slate-200 rounded-xl px-4 py-2 text-sm font-bold text-slate-900 shadow-sm outline-none focus:ring-2 focus:ring-blue-500"
          >
            {[2023, 2024, 2025].map(y => <option key={y} value={y}>{y}</option>)}
          </select>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-4">
            <span className="text-slate-700 font-bold text-sm uppercase tracking-wider">Entradas</span>
            <div className="w-8 h-8 bg-emerald-100 text-emerald-700 rounded-lg flex items-center justify-center">
              <i className="fas fa-arrow-up text-xs"></i>
            </div>
          </div>
          <p className="text-3xl font-black text-slate-900">
            {summary.income.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
          </p>
          <p className="text-xs text-slate-500 mt-2 font-bold">No período selecionado</p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-4">
            <span className="text-slate-700 font-bold text-sm uppercase tracking-wider">Saídas</span>
            <div className="w-8 h-8 bg-rose-100 text-rose-700 rounded-lg flex items-center justify-center">
              <i className="fas fa-arrow-down text-xs"></i>
            </div>
          </div>
          <p className="text-3xl font-black text-slate-900">
            {summary.expense.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
          </p>
          <p className="text-xs text-slate-500 mt-2 font-bold">No período selecionado</p>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-4">
            <span className="text-slate-700 font-bold text-sm uppercase tracking-wider">Saldo em Contas</span>
            <div className="w-8 h-8 bg-blue-100 text-blue-700 rounded-lg flex items-center justify-center">
              <i className="fas fa-wallet text-xs"></i>
            </div>
          </div>
          <p className="text-3xl font-black text-slate-900">
            {totalBalance.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
          </p>
          <p className="text-xs text-slate-500 mt-2 font-bold">Total consolidado hoje</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-black text-slate-900 mb-6">Comparativo Financeiro</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 12, fontWeight: 'bold'}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 12, fontWeight: 'bold'}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', padding: '12px'}}
                />
                <Bar dataKey="faturamento" fill="#10b981" radius={[6, 6, 0, 0]} barSize={24} />
                <Bar dataKey="despesas" fill="#f43f5e" radius={[6, 6, 0, 0]} barSize={24} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between">
          <div>
            <h3 className="text-lg font-black text-slate-900 mb-1">Status Limite MEI {selectedYear}</h3>
            <p className="text-slate-600 font-medium text-sm mb-6">Faturamento acumulado no ano.</p>

            <div className="flex justify-between mb-3">
              <span className="text-sm font-black text-blue-700">
                {currentYearFaturamento.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
              </span>
              <span className="text-sm font-bold text-slate-500">Teto: R$ 81.000</span>
            </div>

            <div className="w-full bg-slate-100 rounded-full h-5 overflow-hidden border border-slate-200">
              <div 
                className={`h-full transition-all duration-1000 ${meiProgress > 90 ? 'bg-rose-500' : meiProgress > 70 ? 'bg-amber-500' : 'bg-blue-600'}`}
                style={{ width: `${meiProgress}%` }}
              ></div>
            </div>

            <div className="mt-6 p-5 bg-blue-50 rounded-2xl text-blue-900 text-sm border border-blue-100">
              <div className="flex items-start space-x-3">
                <i className="fas fa-info-circle mt-1 text-blue-600"></i>
                <div className="font-bold">
                  Você utilizou {meiProgress.toFixed(1)}% do limite. 
                  <p className="mt-1 font-medium opacity-80">Restam {(meiLimit - currentYearFaturamento).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })} para o desenquadramento.</p>
                </div>
              </div>
            </div>
          </div>

          <div className="mt-8 border-t border-slate-100 pt-6">
             <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">Saldos Bancários</h4>
             <div className="space-y-4">
               {accounts.map(acc => (
                 <div key={acc.id} className="flex justify-between items-center bg-slate-50 p-3 rounded-xl">
                   <div className="flex items-center space-x-3">
                     <div className={`w-3 h-3 rounded-full ${acc.color} shadow-sm`}></div>
                     <span className="text-sm font-bold text-slate-800">{acc.name}</span>
                   </div>
                   <span className="text-sm font-black text-slate-900">{acc.balance.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
                 </div>
               ))}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Transaction, TransactionType } from '../types';

interface MeiReportProps {
  transactions: Transaction[];
}

const MeiReport: React.FC<MeiReportProps> = ({ transactions }) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const monthsList = ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'];

  const reportData = useMemo(() => {
    const monthTransactions = transactions.filter(t => {
      const d = new Date(t.date);
      return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
    });

    const revendaMercadorias = monthTransactions
      .filter(t => t.type === TransactionType.INCOME && t.category === 'Venda de Produtos')
      .reduce((sum, t) => sum + t.amount, 0);

    const prestacaoServicos = monthTransactions
      .filter(t => t.type === TransactionType.INCOME && t.category === 'Prestação de Serviços')
      .reduce((sum, t) => sum + t.amount, 0);

    const outrasReceitas = monthTransactions
      .filter(t => t.type === TransactionType.INCOME && t.category === 'Outros')
      .reduce((sum, t) => sum + t.amount, 0);

    const totalReceitaBruta = revendaMercadorias + prestacaoServicos + outrasReceitas;

    return {
      revendaMercadorias,
      prestacaoServicos,
      outrasReceitas,
      totalReceitaBruta
    };
  }, [transactions, selectedMonth, selectedYear]);

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
