      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-100 border-b-2 border-slate-200">
            <tr>
              <th className="px-6 py-4 text-xs font-black text-black uppercase tracking-widest">Data</th>
              <th className="px-6 py-4 text-xs font-black text-black uppercase tracking-widest">Descrição</th>
              <th className="px-6 py-4 text-xs font-black text-black uppercase tracking-widest">Categoria</th>
              <th className="px-6 py-4 text-xs font-black text-black uppercase tracking-widest">Conta</th>
              <th className="px-6 py-4 text-xs font-black text-black uppercase tracking-widest text-right">Valor</th>
              <th className="px-6 py-4 text-xs font-black text-black uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y-2 divide-slate-100">
            {filtered.length === 0 ? (
              <tr>
                <td colSpan={6} className="px-6 py-12 text-center text-black font-black">
                  <i className="fas fa-receipt text-4xl mb-3 block text-slate-400"></i>
                  Nenhum lançamento encontrado.
                </td>
              </tr>
            ) : (
              filtered.map((tx) => (
                <tr key={tx.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-black font-black">
                    {new Date(tx.date).toLocaleDateString('pt-BR')}
                  </td>
                  <td className="px-6 py-4 text-sm font-black text-black">
                    {tx.description}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="px-3 py-1 text-xs font-black rounded-md bg-slate-200 text-black border border-slate-300">
                      {tx.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-black font-bold">
                    {getAccountName(tx.accountId)}
                  </td>
                  <td className={`px-6 py-4 whitespace-nowrap text-sm font-black text-right ${tx.type === TransactionType.INCOME ? 'text-emerald-700' : 'text-rose-700'}`}>
                    {tx.type === TransactionType.INCOME ? '+' : '-'} {tx.amount.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <button 
                      onClick={() => onDelete(tx.id)}
                      className="text-black hover:text-rose-700 transition-colors p-2"
                      title="Excluir lançamento"
                    >
                      <i className="fas fa-trash-alt"></i>
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

