export interface AppState {
  transactions: Transaction[];
  accounts: Account[];
  user: User | null;
}

import React, { useState, useEffect } from 'react';
import { User, Transaction, Account, TransactionType } from './types';
import { INITIAL_ACCOUNTS, INITIAL_TRANSACTIONS } from './constants';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import AccountManager from './components/AccountManager';
import Navbar from './components/Navbar';
import AddTransactionModal from './components/AddTransactionModal';
import MeiReport from './components/MeiReport';
import Settings from './components/Settings';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'dashboard' | 'transactions' | 'accounts' | 'reports' | 'settings'>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('mei_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [accounts, setAccounts] = useState<Account[]>(() => {
    const saved = localStorage.getItem('mei_accounts');
    return saved ? JSON.parse(saved) : INITIAL_ACCOUNTS;
  });
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  useEffect(() => {
    const savedUser = localStorage.getItem('mei_user');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  useEffect(() => {
    localStorage.setItem('mei_transactions', JSON.stringify(transactions));
    localStorage.setItem('mei_accounts', JSON.stringify(accounts));
    if (user) localStorage.setItem('mei_user', JSON.stringify(user));
  }, [transactions, accounts, user]);

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('mei_user', JSON.stringify(userData));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('mei_user');
  };

  const updateUserSettings = (updatedUser: User) => {
    setUser(updatedUser);
  };

  const addTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const id = Math.random().toString(36).substr(2, 9);
    const tx = { ...newTx, id };

    setTransactions(prev => [tx, ...prev]);

    setAccounts(prev => prev.map(acc => {
      if (acc.id === tx.accountId) {
        const change = tx.type === TransactionType.INCOME ? tx.amount : -tx.amount;
        return { ...acc, balance: acc.balance + change };
      }
      return acc;
    }));

    setIsAddModalOpen(false);
  };

  const deleteTransaction = (id: string) => {
    const tx = transactions.find(t => t.id === id);
    if (!tx) return;

    setTransactions(prev => prev.filter(t => t.id !== id));

    setAccounts(prev => prev.map(acc => {
      if (acc.id === tx.accountId) {
        const revert = tx.type === TransactionType.INCOME ? -tx.amount : tx.amount;
        return { ...acc, balance: acc.balance + revert };
      }
      return acc;
    }));
  };

  const updateAccount = (updatedAcc: Account) => {
    setAccounts(prev => prev.map(acc => acc.id === updatedAcc.id ? updatedAcc : acc));
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Navbar 
        activeView={view} 
        setView={setView} 
        onLogout={handleLogout} 
        userName={user.meiName}
      />

      <main className="flex-grow container mx-auto px-4 py-8 pb-24 md:pb-8">
        {view === 'dashboard' && (
          <Dashboard transactions={transactions} accounts={accounts} />
        )}
        {view === 'transactions' && (
          <TransactionList 
            transactions={transactions} 
            accounts={accounts}
            onDelete={deleteTransaction} 
          />
        )}
        {view === 'accounts' && (
          <AccountManager accounts={accounts} onUpdateAccount={updateAccount} />
        )}
        {view === 'reports' && (
          <MeiReport transactions={transactions} />
        )}
        {view === 'settings' && (
          <Settings user={user} onUpdate={updateUserSettings} />
        )}
      </main>

      <button 
        onClick={() => setIsAddModalOpen(true)}
        className="fixed bottom-24 right-6 md:bottom-8 md:right-8 w-14 h-14 bg-blue-600 text-white rounded-full shadow-lg flex items-center justify-center text-2xl hover:bg-blue-700 transition-all z-40"
      >
        <i className="fas fa-plus"></i>
      </button>

      {isAddModalOpen && (
        <AddTransactionModal 
          onClose={() => setIsAddModalOpen(false)}
          onSubmit={addTransaction}
          accounts={accounts}
        />
      )}

      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex justify-around items-center py-3 z-30">
        <button onClick={() => setView('dashboard')} className={`flex flex-col items-center ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-500'}`}>
          <i className="fas fa-home text-xl"></i>
          <span className="text-[10px] mt-1 font-bold">Início</span>
        </button>
        <button onClick={() => setView('transactions')} className={`flex flex-col items-center ${view === 'transactions' ? 'text-blue-600' : 'text-slate-500'}`}>
          <i className="fas fa-exchange-alt text-xl"></i>
          <span className="text-[10px] mt-1 font-bold">Lançamentos</span>
        </button>
        <button onClick={() => setView('reports')} className={`flex flex-col items-center ${view === 'reports' ? 'text-blue-600' : 'text-slate-500'}`}>
          <i className="fas fa-file-invoice-dollar text-xl"></i>
          <span className="text-[10px] mt-1 font-bold">Relatórios</span>
        </button>
        <button onClick={() => setView('settings')} className={`flex flex-col items-center ${view === 'settings' ? 'text-blue-600' : 'text-slate-500'}`}>
          <i className="fas fa-cog text-xl"></i>
          <span className="text-[10px] mt-1 font-bold">Config</span>
        </button>
      </div>
    </div>
  );
};

export default App;

