}

const MeiReport: React.FC<MeiReportProps> = ({ transactions }) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const monthsList = ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'];

  const reportData = useMemo(() => {
    const monthTransactions = transactions.filter(t => {
      const d = new Date(t.date);
      return d.getMonth() === selectedMonth && d.getFullYear() === selectedYear;
    });

    const revendaMercadorias = monthTransactions
      .filter(t => t.type === TransactionType.INCOME && t.category === 'Venda de Produtos')
      .reduce((sum, t) => sum + t.amount, 0);

    const prestacaoServicos = monthTransactions
      .filter(t => t.type === TransactionType.INCOME && t.category === 'Prestação de Serviços')
      .reduce((sum, t) => sum + t.amount, 0);

    const industrializacao = 0;

    return {
      revendaMercadorias,
      industrializacao,
      prestacaoServicos,
      total: revendaMercadorias + industrializacao + prestacaoServicos
    };
  }, [transactions, selectedMonth, selectedYear]);

  const handlePrint = () => {
    window.print();
  };

  const formatCurrency = (val: number) => {
    return val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };

  const savedUser = JSON.parse(localStorage.getItem('mei_user') || '{}');

  return (
    <div className="max-w-4xl mx-auto py-4">
      <style>
        {`
          @media print {
            .print-area * {
              color: #000000 !important;
              border-color: #000000 !important;
