                  <td className="px-6 py-4 whitespace-nowrap text-sm text-black font-black">
                    {new Date(tx.date).toLocaleDateString('pt-BR')}
                  </td>
                  <td className="px-6 py-4 text-sm font-black text-black">
                    {tx.description}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="px-3 py-1 text-xs font-black rounded-md bg-slate-200 text-black border border-slate-300">
                      {tx.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-black font-bold">
                    {getAccountName(tx.accountId)}
                  </td>
                  <td className={`px-6 py-4 whitespace-nowrap text-sm font-black text-right ${tx.type === TransactionType.INCOME ? 'text-emerald-700' : 'text-rose-700'}`}>
                    {tx.type === TransactionType.INCOME ? '+' : '-'} {tx.amount.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right space-x-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="text-black hover:text-blue-700 transition-colors p-2"
                      title="Editar lançamento"
                    >
                      <i className="fas fa-edit"></i>
                    </button>
                    <button 
                      onClick={() => onDelete(tx.id)}
                      className="text-black hover:text-rose-700 transition-colors p-2"
                      title="Excluir lançamento"
                    >
                      <i className="fas fa-trash-alt"></i>
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

